#![no_std]

multiversx_sc::imports!();

pub mod very_large_storage_proxy;

const FULL_CYCLE: [u8; 256] = {
    let mut arr = [0u8; 256];
    let mut i = 0usize;
    while i < 256 {
        arr[i] = i as u8;
        i += 1;
    }
    arr
};

/// Benchmark contract with a single large storage entry.
/// The `append` endpoint generates bytes cycling 0x00..=0xff and appends them to storage.
#[multiversx_sc::contract]
pub trait VeryLargeStorage {
    #[init]
    fn init(&self) {}

    /// Appends `num_bytes` bytes to the storage entry `x`.
    /// The generated bytes cycle through 0x00..=0xff.
    #[endpoint(append)]
    fn append(&self, num_bytes: u64) {
        let full_cycles = num_bytes / 256;
        let remainder = (num_bytes % 256) as usize;

        self.x().update(|x| {
            for _ in 0..full_cycles {
                x.append_bytes(&FULL_CYCLE[..]);
            }
            if remainder > 0 {
                x.append_bytes(&FULL_CYCLE[..remainder]);
            }
        });
    }

    /// Returns the number of bytes stored in `x`.
    #[view(getXLen)]
    fn x_len(&self) -> usize {
        self.x().raw_byte_length()
    }

    #[view(getX)]
    #[storage_mapper("x")]
    fn x(&self) -> SingleValueMapper<ManagedBuffer>;
}
